import type SharedTemplateMetadata from "../../editing/sharedTemplates/SharedTemplateMetadata.js";
import type FeatureTemplate from "../../layers/support/FeatureTemplate.js";
import type { LayerWithFeatureTemplatesUnion } from "../../layers/types.js";

/**
 * The function used when setting the [FeatureTemplates.groupBy](https://developers.arcgis.com/javascript/latest/references/core/widgets/FeatureTemplates/#groupBy) property. It is
 * used to customize the grouping of [template items](https://developers.arcgis.com/javascript/latest/references/core/widgets/FeatureTemplates/TemplateItem/). This can aid
 * in managing various template items and how they display within the widget. This takes an object containing a
 * `template` and a `layer` property.
 *
 * @param grouping - An object containing the properties referenced below.
 * @returns Groups consist of a group `key` and `label`. These are shown in the UI. If both
 * the `key` and `label` are identical, return a `string`. Otherwise, return an `object` with
 * `key/name` properties. This gives finer control of the groups.
 * @since 5.0
 * @example
 * // This example shows using a function to check if
 * // the layer title contains the word 'military'. If so,
 * // return a group of items called "All Military Templates"
 * function customGroup(grouping) {
 *   // Consolidate all military layers
 *   if (grouping.layer.title.toLowerCase().indexOf("military") > -1) {
 *     return "All Military Templates"
 *   }
 * // Otherwise, group by layer title
 *   return grouping.layer.title;
 * }
 *
 * // Create the FeatureTemplates widget
 * templates = new FeatureTemplates({
 *   container: "templatesDiv",
 *   layers: layers,
 *   groupBy: customGroup
 * });
 * @example
 * // Group template items by layers.
 * // This function is as same as setting
 * // the groupBy property to "layer" option.
 * function groupByLayer (grouping) {
 *   const group = {
 *     key: grouping.layer,
 *     name: grouping.layer.title
 *   };
 *   return group;
 * }
 *
 * // Create the FeatureTemplates widget
 * const templates = new FeatureTemplates({
 *   container: "templatesDiv",
 *   layers: layers,
 *   groupBy: groupByLayer
 * });
 */
export type GroupByFunction<T = any> = (grouping: GroupByFunctionGrouping) => object;

/** @since 5.0 */
export interface GroupByFunctionGrouping {
  /**
   * [FeatureTemplate](https://developers.arcgis.com/javascript/latest/references/core/layers/support/FeatureTemplate/) associated with the `layer`.
   *
   * @since 5.0
   */
  template: FeatureTemplate | SharedTemplateMetadata;
  /**
   * [FeatureLayer](https://developers.arcgis.com/javascript/latest/references/core/layers/FeatureLayer/) instance referenced in [FeatureTemplates.layers](https://developers.arcgis.com/javascript/latest/references/core/widgets/FeatureTemplates/#layers) property.
   *
   * @since 5.0
   */
  layer: LayerWithFeatureTemplatesUnion;
}

/** @since 5.0 */
export type GroupByType = "none" | "layer" | "geometry" | GroupByFunction;

/**
 * The filter used when setting the [FeatureTemplates.filterFunction](https://developers.arcgis.com/javascript/latest/references/core/widgets/FeatureTemplates/#filterFunction)
 * property. It takes an object containing a [name](https://developers.arcgis.com/javascript/latest/references/core/widgets/FeatureTemplates/TemplateItem/#label)
 * property of the [template item](https://developers.arcgis.com/javascript/latest/references/core/widgets/FeatureTemplates/TemplateItem/) and returns
 * whether or not to include it.
 *
 * @param filterName - An object containing a `name` property.
 * @returns Function is a predicate, to test each element of the array.
 * Return `true` to keep [item](https://developers.arcgis.com/javascript/latest/references/core/widgets/FeatureTemplates/TemplateItem/) in the template widget, otherwise, `false`
 * to remove it.
 * @since 5.0
 * @example
 * // Filter and display templates only if their labels contain the word `Street`
 * function myFilterFunction(filter) {
 *   let containsName = filter.label.includes("Street");
 *   return containsName;
 * }
 *
 * // Create the FeatureTemplates widget
 * templates = new FeatureTemplates({
 *   container: "templatesDiv",
 *   visibleElements: {
 *     filter: false, // disable the default filter UI
 *   }
 *   layers: [featureLayer], // in this example, one layer is used
 *   filterFunction: myFilterFunction
 * });
 */
export type Filter = (filterName: FilterFilterName) => boolean;

/** @since 5.0 */
export interface FilterFilterName {
  /**
   * The [name](https://developers.arcgis.com/javascript/latest/references/core/widgets/FeatureTemplates/TemplateItem/#label)
   * of the [template item](https://developers.arcgis.com/javascript/latest/references/core/widgets/FeatureTemplates/TemplateItem/) to filter.
   *
   * @since 5.0
   */
  label?: string | null;
}